#nullable enable // autogenerated  

using MVZ2.GameContent.Buffs.Enemies;
using MVZ2.GameContent.Damages;
using MVZ2.Vanilla.Enemies;
using MVZ2.Vanilla.Entities;
using MVZ2.Vanilla.Level;
using PVZEngine.Buffs;
using PVZEngine.Damages;
using PVZEngine.Entities;
using PVZEngine.Level;
using PVZEngine.Definitions;
using PVZEngine.Callbacks;
using MVZ2.Vanilla.Properties;
using MVZ2.GameContent.Effects;
using UnityEngine;

namespace MVZ2.GameContent.Enemies
{
    [AutoEntityBehaviourDefinition(VanillaEnemyNames.TorchKongfuZombie)]
    public class TorchKongfuZombie : MonkZombie
    {
        // 魹ｽ魹ｽ魹ｽ魹ｽﾇｷ魹ｽ魹ｽﾈｼ魹ｽ魹ｽﾗｴﾌｬ魹ｽ魹ｽ魹ｽ魹ｽ  
        private bool isTorchLit = true;

        public TorchKongfuZombie(string nsp, string name) : base(nsp, name)
        {
        }

        public override void Init(Entity entity)
        {
            base.Init(entity);
            // 魹ｽ魹ｽﾊｼ魹ｽ魹ｽﾊｱ魹ｽ魹ｽ魹ｽ魹ｽﾇｵ魹ｽﾈｼ魹ｽ魹ｽ  
            isTorchLit = true;
        }

        public override void PreTakeDamage(DamageInput input, CallbackResult result)
        {
            base.PreTakeDamage(input, result);

            // 魹ｽ魹ｽ魹ｽ魹ｽﾇｷ魹ｽ魹ｽﾜｵ魹ｽ魹ｽ魹ｽ魹ｽﾋｺ魹ｽ  
            if (input.Effects.HasEffect(VanillaDamageEffects.ICE))
            {
                // 魹ｽ魹ｽ魹ｽﾏｨ魹ｽ魹ｽ  
                isTorchLit = false;
            }

            // 魹ｽ魹ｽ魹ｽ魹ｽﾇｷ魹ｽ魹ｽﾜｵ魹ｽ魹ｽ魹ｽ魹ｽﾋｺ魹ｽ  
            if (input.Effects.HasEffect(VanillaDamageEffects.FIRE))
            {
                // 魹ｽ魹ｽﾑｵ魹ｽﾈｼ  
                isTorchLit = true;
            }
        }

        protected override void UpdateLogic(Entity entity)
        {
            base.UpdateLogic(entity);
            entity.SetModelDamagePercent();

            // ﾊｾ魹ｽ魹ｽ魹ｽ魹ｽ魹ｽ魹ｽﾄｳ魹ｽ魹ｽ魹ｽ魹ｽ魹ｽ魹ｽ魹ｽﾂｵ魹ｽ魹ｽ魹ｽ FireAOE魹ｽ魹ｽ魹ｽ魹ｽ魹ｽ魹ｽ魹ｽﾒｪ魹ｽ魹ｽ  
            // ﾖｻ魹ｽ魹ｽ魹ｽﾚｻ魹ｽﾑｵ魹ｽﾈｼﾊｱ魹ｽ魹ｽ魹ｽ魹ｽﾊｹ魹ｽ魹ｽ FireAOE  
            if (isTorchLit)
            {
                FireAOE(entity, 6.67f, entity.GetFaction());
            }
        }

        public static void FireAOE(Entity entity, float damage, int faction)
        {
            var range = 40;

            var damageOutputs = entity.Explode(
                entity.GetCenter(),
                range,
                faction,
                damage,
                new DamageEffectList(VanillaDamageEffects.DAMAGE_BOTH_ARMOR_AND_BODY, VanillaDamageEffects.MUTE, VanillaDamageEffects.FIRE)
            );

            foreach (var output in damageOutputs)
            {
                if (output?.Entity != null)
                {
                    float offsetX = UnityEngine.Random.Range(-20f, 20f);
                    float offsetY = UnityEngine.Random.Range(-20f, 20f);
                    Vector3 spawnPos = output.Entity.Position + new Vector3(offsetX, offsetY, 0);

                    entity.Spawn(VanillaEffectID.fireburn, spawnPos);
                }
            }
        }

        // 魹ｽ魹ｽﾑ｡魹ｽ魹ｽ魹ｽ盪ｩﾒｻ魹ｽ魹ｽ魹ｽ魹ｽ魹ｽ魹ｽ魹ｽ魹ｽ魹ｽ箚ｿ魹ｽ魹ｽ魹ｽ魹ｽ魹ｽﾗｴﾌｬ  
        public bool IsTorchLit()
        {
            return isTorchLit;
        }
    }
}